code = """import json
import re

# Load data
package_data = json.load(open(locals()['var_functions.query_db:5'], 'r'))
project_package_data = json.load(open(locals()['var_functions.query_db:6'], 'r'))
project_info_data = json.load(open(locals()['var_functions.query_db:18'], 'r'))

# Build package lookup: System, Name, Version
package_lookup = {}
for pkg in package_data:
    if pkg['System'] == 'NPM' and 'MIT' in pkg['Licenses']:
        try:
            vi = json.loads(pkg['VersionInfo'])
            if vi.get('IsRelease'):
                key = (pkg['System'], pkg['Name'], pkg['Version'])
                package_lookup[key] = pkg
        except:
            pass

# Build project info lookup: project_name -> forks
project_info_lookup = {}
for proj in project_info_data:
    text = proj['Project_Information']
    # Extract project name (owner/repo)
    match = re.search(r'([a-zA-Z0-9_-]+/[a-zA-Z0-9_-]+)', text)
    if match:
        pname = match.group(1).lower()
        fork_match = re.search(r'(\d+)\s+forks?', text, re.IGNORECASE)
        forks = int(fork_match.group(1)) if fork_match else 0
        project_info_lookup[pname] = forks

# Match packages with projects
matched = {}
for pp in project_package_data:
    if pp['System'] == 'NPM':
        key = (pp['System'], pp['Name'], pp['Version'])
        if key in package_lookup:
            gh_proj = pp.get('ProjectName', '').lower()
            if gh_proj in project_info_lookup:
                if gh_proj not in matched or project_info_lookup[gh_proj] > matched[gh_proj]['forks']:
                    matched[gh_proj] = {
                        'project': gh_proj,
                        'forks': project_info_lookup[gh_proj],
                        'package_name': pp['Name']
                    }

# Get top 5
top_5 = sorted(matched.values(), key=lambda x: x['forks'], reverse=True)[:5]

print('__RESULT__:')
print(json.dumps(top_5, indent=2))"""

